import React, { useCallback, useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import {
  findUserByName,
  retrieveAllUsers,
  deactivateUser,
  activateUser,
} from "../../slices/users";
import Pagination, { ITEMS_PER_PAGE } from "../Pagination";

const StaffList = () => {
  const [searchName, setSearchName] = useState("");
  const { reviewers, users } = useSelector((state) => state.user);
  console.log("🚀 ~ file: StaffList.js:15 ~ StaffList ~ users:", users);
  const dispatch = useDispatch();
  const [currentPage, setCurrentPage] = useState(1);

  const onChangeSearchName = (e) => {
    const searchName = e.target.value;
    setSearchName(searchName);
  };

  const onSearchSubmit = (e) => {
    if (e.code === "Enter") {
      findByName();
    }
  };

  const initFetch = useCallback(() => {
    dispatch(retrieveAllUsers());
  }, [dispatch]);

  useEffect(() => {
    initFetch();
  }, [initFetch]);

  const findByName = () => {
    setCurrentPage(1);
    dispatch(findUserByName({ name: searchName }));
  };

  const handleDeactivate = (id) => {
    if (!window.confirm("Are you sure you want to deactivate this user?"))
      return;
    dispatch(deactivateUser({ id }))
      .unwrap()
      .catch((e) => console.log(e));
  };

  const handleActivate = (id) => {
    if (!window.confirm("Are you sure you want to reactivate this user?"))
      return;
    dispatch(activateUser({ id }))
      .unwrap()
      .catch((e) => console.log(e));
  };

  return (
    <div className=" row">
      <div className="col-md-12">
        <div className="input-group mb-3">
          <input
            type="text"
            className="form-control"
            placeholder="Search by description"
            value={searchName}
            onChange={onChangeSearchName}
            onKeyPress={onSearchSubmit}
          />
          <div className="input-group-append">
            <button
              className="btn btn-outline-secondary"
              type="button"
              onClick={findByName}
            >
              Search
            </button>
          </div>
        </div>
      </div>
      <div className="col-md-12">
        <h4>user List</h4>
      </div>
      {/* user list table start */}
      <div className="col-md-2 table-responsive-md"></div>
      <div className="col-md-8 tableFixHead">
        {users && (
          <table className="table table-striped">
            <thead>
              <tr>
                <th scope="col">#</th>
                <th scope="col">User</th>
                <th scope="col">Status</th>
                <th scope="col" colSpan="2">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody>
              {users
                .slice(
                  (currentPage - 1) * ITEMS_PER_PAGE,
                  currentPage * ITEMS_PER_PAGE,
                )
                .map((user, index) => {
                  return (
                    <tr
                      key={`user-row-${index}`}
                      className={
                        user.isActive === false ? "table-secondary" : ""
                      }
                    >
                      <td>{(currentPage - 1) * ITEMS_PER_PAGE + index + 1}</td>
                      <td>{user.username}</td>
                      <td>
                        <span
                          className={`badge ${user.isActive === false ? "badge-secondary" : "badge-success"}`}
                          style={{
                            padding: "4px 8px",
                            borderRadius: "10px",
                            fontSize: "0.75rem",
                          }}
                        >
                          {user.isActive === false ? "Inactive" : "Active"}
                        </span>
                      </td>
                      <td colSpan="2">
                        <div style={{ display: "inline-flex" }}>
                          <Link
                            to={"/users/" + user.id}
                            className="btn btn-sm btn-warning mr-2 mt-0"
                          >
                            Edit
                          </Link>
                          {user.isActive === false ? (
                            <button
                              className="btn btn-sm btn-success mr-2 mt-0"
                              onClick={() => handleActivate(user.id)}
                            >
                              Activate
                            </button>
                          ) : (
                            <button
                              className="btn btn-sm btn-danger mr-2 mt-0"
                              onClick={() => handleDeactivate(user.id)}
                            >
                              Deactivate
                            </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
            </tbody>
          </table>
        )}
      </div>
      <div className="col-md-2 table-responsive-md"></div>
      {/* user list table end */}
      {users && users.length > ITEMS_PER_PAGE && (
        <div className="col-md-12 d-flex justify-content-center mt-2">
          <Pagination
            currentPage={currentPage}
            totalItems={users.length}
            onPageChange={setCurrentPage}
          />
        </div>
      )}
      <div className="col-md-10">
        {users.length === 0 && (
          <div className="d-flex justify-content-center">
            <h5 className="text-center text-info">No Users Found</h5>
          </div>
        )}
      </div>
    </div>
  );
};

export default StaffList;
